// Evaluate F_m(T) for m <= kBoysLutMmax and T in [0, kBoysLutTmax]
// using Clenshaw recurrence on the pre-computed Chebyshev coefficients.
template <int MMAX>
__device__ inline void boys_fm_lut(double T, double* F) {
  // For T > T_max, fall back to asymptotic + upward recurrence.
  if (T > kBoysLutTmax) {
    const double invT = 1.0 / T;
    const double e = ::exp(-T);
    F[0] = 0.5 * ::sqrt(kPi * invT) * ::erf(::sqrt(T));
    #pragma unroll
    for (int m = 1; m <= MMAX; ++m) {
      F[m] = ((2 * m - 1) * F[m - 1] - e) * (0.5 * invT);
    }
    return;
  }

  // Determine interval index
  int interval = static_cast<int>(T * kBoysLutInvDT);
  if (interval >= kBoysLutNintervals) interval = kBoysLutNintervals - 1;

  // Map T to u in [-1, 1] within the interval
  const double a = static_cast<double>(interval) * kBoysLutDT;
  const double u = 2.0 * (T - a) * kBoysLutInvDT - 1.0;

  // Evaluate each F_m via Clenshaw recurrence
  #pragma unroll
  for (int m = 0; m <= MMAX; ++m) {
    const int base = m * (200 * 8) + interval * 8;
    double bk1 = 0.0, bk2 = 0.0;
    #pragma unroll
    for (int j = 7; j >= 1; --j) {
      const double bk0 = __ldg(&kBoysLutCoeffs[base + j]) + 2.0 * u * bk1 - bk2;
      bk2 = bk1;
      bk1 = bk0;
    }
    F[m] = __ldg(&kBoysLutCoeffs[base]) + u * bk1 - bk2;
  }
}

